#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
from datetime import datetime
from pathlib import Path
from typing import Any

from report_io import atomic_write_text

WORKSPACE = Path.home() / ".openclaw" / "workspace"
REPORT_DIR = WORKSPACE / "research" / "reports"
DELIVERY_CONFIG = WORKSPACE / "config" / "investment_research_delivery_v1.json"
CHAT_CONFIG = WORKSPACE / "config" / "investment_research_group_chat_orchestrator_v1.json"

MEETING_LABELS = {
    "morning": "盘前会",
    "midday": "午盘巡检",
    "close": "收盘复盘",
    "night": "夜间研究会",
}

ROLE_LABELS = {
    "macro_researcher": "🌍 宏观研究员",
    "industry_researcher": "🏭 行业研究员",
    "quant_analyst": "📊 量化分析师",
    "risk_officer": "🛡 风控官",
    "trader": "⚡ 交易员",
    "chief_researcher": "👨💼 首席研究员",
    "buffett_avatar": "💰 巴菲特分身",
    "soros_avatar": "🎯 索罗斯分身",
}


def load_json(path: Path) -> dict[str, Any]:
    return json.loads(path.read_text(encoding="utf-8"))


def today_tag() -> str:
    return datetime.now().strftime("%Y%m%d")


def required_path(prefix: str, meeting_type: str, suffix: str) -> Path:
    p = REPORT_DIR / f"{prefix}_{meeting_type}_{today_tag()}.{suffix}"
    if not p.exists():
        raise FileNotFoundError(str(p))
    return p


def role_brief_index(meeting_type: str) -> dict[str, Any]:
    p = REPORT_DIR / f"investment_research_role_briefs_index_{meeting_type}_{today_tag()}.json"
    return load_json(p) if p.exists() else {"outputs": []}


def role_brief_map(meeting_type: str) -> dict[str, dict[str, Any]]:
    outputs = role_brief_index(meeting_type).get("outputs", [])
    result: dict[str, dict[str, Any]] = {}
    for item in outputs:
        result[item["role_id"]] = load_json(Path(item["json"]))
    return result


def unique_join(items: list[str]) -> str:
    return ", ".join(dict.fromkeys(item for item in items if item)) or "无"


def clean_points(lines: list[str]) -> list[str]:
    points: list[str] = []
    for line in lines:
        s = line.strip()
        if not s:
            continue
        if "输入边界" in s or s.startswith("- 允许来源") or s.startswith("- 禁止读取"):
            continue
        if s.startswith("-"):
            s = s[1:].strip()
        if s.startswith("事实：") or s.startswith("判断：") or s.startswith("建议：") or s.startswith("风险：") or s.startswith("否决条件："):
            points.append(s)
    return points


def select_stage_points(points: list[str], max_points: int) -> list[str]:
    preferred_prefixes = ["判断：", "建议：", "否决条件：", "风险：", "事实："]
    selected: list[str] = []
    for prefix in preferred_prefixes:
        for item in points:
            if item.startswith(prefix) and item not in selected:
                selected.append(item)
                if len(selected) >= max_points:
                    return selected
    return selected[:max_points]


def stage_one_message(role_id: str, role_json: dict[str, Any], previous_summary: str | None, max_points: int = 2) -> tuple[str, str]:
    label = ROLE_LABELS.get(role_id, role_id)
    points = clean_points(role_json.get("lines", []))
    selected = select_stage_points(points, max_points) if points else ["暂无有效观点"]
    lines: list[str] = []
    if previous_summary:
        lines.append(f"- 接着上一位结论：{previous_summary}")
    for item in selected:
        lines.append(f"- {item}")
    summary_source = next((item for item in selected if item.startswith("判断：") or item.startswith("建议：") or item.startswith("否决条件：")), selected[0])
    summary = summary_source.replace("事实：", "").replace("判断：", "").replace("建议：", "").replace("风险：", "").replace("否决条件：", "")
    return f"{label}\n" + "\n".join(lines), summary[:80]


def chief_stage_message(report: dict[str, Any], trade_card: dict[str, Any]) -> str:
    debate = report.get("debate_snapshot", {})
    ruling = debate.get("chief_ruling", {})
    supporters = unique_join(ruling.get("supporters", []))
    opponents = unique_join(ruling.get("opponents", []))
    vetoes = unique_join(ruling.get("vetoes", []))
    watchlist = "、".join(ruling.get("priority_watchlist", [])[:5]) or str(trade_card.get("watchlist_reason") or "暂无")
    lines = [
        "👨💼 首席研究员",
        f"- 支持方：{supporters}",
        f"- 反对方：{opponents}",
        f"- 否决方：{vetoes}",
        f"- 最终裁决：{ruling.get('final_ruling', 'unknown')}",
        f"- 观察池：{watchlist}",
    ]
    if not trade_card.get("trading_time", False):
        lines.append("- 当前非交易时段/非交易日，只保留方向、预算和开盘触发条件，不给可执行买价。")
    for cond in ruling.get("ruling_conditions", [])[:3]:
        lines.append(f"- 裁决条件：{cond}")
    return "\n".join(lines)


def build_digest(meeting_type: str) -> str:
    delivery = load_json(DELIVERY_CONFIG)
    chat_cfg = load_json(CHAT_CONFIG) if CHAT_CONFIG.exists() else {}
    report = load_json(required_path("investment_research_org_orchestrated", meeting_type, "json"))
    trade_card = load_json(required_path("investment_research_trade_card", meeting_type, "json"))
    briefs = role_brief_map(meeting_type)
    stage_one_roles = chat_cfg.get("stage_one_roles", ["macro_researcher", "industry_researcher", "quant_analyst", "risk_officer", "trader"])
    max_points = chat_cfg.get("max_stage_one_points", 2)

    lines: list[str] = []
    lines.append(f"【来福投研会｜{MEETING_LABELS.get(meeting_type, meeting_type)}｜两阶段编排】")
    lines.append("")
    lines.append("第一阶段｜角色短发言")

    previous_summary: str | None = None
    for role_id in stage_one_roles:
        role_json = briefs.get(role_id)
        if not role_json:
            continue
        msg, previous_summary = stage_one_message(role_id, role_json, previous_summary, max_points=max_points)
        lines.append(msg)
        lines.append("")

    lines.append("第二阶段｜首席研究员裁决")
    lines.append(chief_stage_message(report, trade_card))
    lines.append("")

    watchlist = [x.get("display", x["ticker"]) for x in trade_card.get("watchlist", [])]
    watchlist_text = "、".join(watchlist) if watchlist else (trade_card.get("watchlist_reason") or "暂无")
    sell_review = trade_card.get("sell_review_list", [])[:5]
    lines.append("附：交易建议卡")
    lines.append(f"- 状态：{trade_card.get('status', 'unknown')}")
    lines.append(f"- 观察池：{watchlist_text}")
    lines.append(f"- 条件试探仓总预算：{trade_card.get('conditional_probe_total_budget_pct', '-') }%")
    if sell_review:
        lines.append(f"- 卖出/减仓复核：{'、'.join(sell_review)}")
    elif trade_card.get("sell_review_reason"):
        lines.append(f"- 卖出/减仓复核：{trade_card.get('sell_review_reason')}")
    if not trade_card.get("trading_time", False):
        lines.append("- 当前非交易时段/非交易日，不提供可执行买价")
    lines.append("- 模式 B：必须用户确认后才能进入执行层")
    lines.append("- 输出方式：两阶段编排")
    return "\n".join(lines) + "\n"


def main() -> None:
    ap = argparse.ArgumentParser(description="Generate group-ready digest for investment research org")
    ap.add_argument("--meeting-type", choices=["morning", "midday", "close", "night"], default="morning")
    ap.add_argument("--output", help="output markdown path")
    args = ap.parse_args()

    text = build_digest(args.meeting_type)
    output = Path(args.output) if args.output else REPORT_DIR / f"investment_research_group_digest_{args.meeting_type}_{today_tag()}.md"
    atomic_write_text(output, text, encoding="utf-8")
    print(output)


if __name__ == "__main__":
    main()

