#!/usr/bin/env python3
"""
真实账户持仓同步脚本
将 account_holdings_*.csv 转换为 paper_portfolio_positions_latest.csv
对接入投研组织系统
"""

import csv
import sys
from datetime import datetime
from pathlib import Path

QUANT_REPORTS = Path.home() / ".openclaw" / "workspace" / "quant_projects" / "personal-a-share-research-system" / "research" / "reports"
WORKSPACE_REPORTS = Path.home() / ".openclaw" / "workspace" / "research" / "reports"


def read_rows(path: Path):
    rows = []
    try:
        with path.open(newline="", encoding="utf-8-sig") as f:
            reader = csv.DictReader(f)
            for row in reader:
                if not row:
                    continue
                if not any(str(v or "").strip() for v in row.values()):
                    continue
                if not (row.get("ts_code") or "").strip():
                    continue
                rows.append(row)
    except Exception:
        return []
    return rows


def list_account_snapshots():
    ordered = []
    preferred = [
        QUANT_REPORTS / "account_holdings_selected_latest.csv",
        *sorted(QUANT_REPORTS.glob("account_holdings_selected_????????.csv"), key=lambda p: p.stat().st_mtime, reverse=True),
    ]
    seen = set()
    for f in preferred:
        if not f.exists():
            continue
        if f.resolve() in seen:
            continue
        seen.add(f.resolve())
        ordered.append(f)
    snapshots = []
    for f in ordered:
        rows = read_rows(f)
        if rows:
            snapshots.append((f, rows))
    return snapshots


def select_source_snapshot(snapshots):
    """
    选择同步源，带异常收缩防护：
    - 默认使用最新文件
    - 若最新持仓 < 最近7份最大持仓的70%（且最大>=10），回退到该最大持仓文件
    """
    if not snapshots:
        return None, None

    latest_file, latest_rows = snapshots[0]
    latest_count = len(latest_rows)

    recent = snapshots[:7]
    baseline_file, baseline_rows = max(recent, key=lambda item: len(item[1]))
    baseline_count = len(baseline_rows)

    threshold = max(5, int(round(baseline_count * 0.7)))
    fallback_used = baseline_count >= 10 and latest_count < threshold

    if fallback_used:
        meta = {
            "fallback_used": True,
            "latest_file": latest_file.name,
            "latest_count": latest_count,
            "selected_file": baseline_file.name,
            "selected_count": baseline_count,
            "reason": (
                f"最新文件{latest_file.name}仅{latest_count}只，低于最近窗口最大{baseline_count}只的70%阈值({threshold})，"
                "疑似同步异常，已回退"
            ),
        }
        return baseline_file, meta

    meta = {
        "fallback_used": False,
        "latest_file": latest_file.name,
        "latest_count": latest_count,
        "selected_file": latest_file.name,
        "selected_count": latest_count,
        "reason": "",
    }
    return latest_file, meta


def normalize_rows(rows):
    out = []
    for row in rows:
        ts_code = (row.get("ts_code") or "").strip()
        if not ts_code:
            continue

        currency = (row.get("currency") or "CNY").strip().upper()
        name = (row.get("name") or "").strip()
        if currency == "HKD":
            asset_type = "hk"
        elif "ETF" in name.upper() or "ETF" in ts_code.upper():
            asset_type = "etf"
        else:
            asset_type = "stock"

        try:
            quantity = int(float(str(row.get("qty") or "0").strip()))
        except Exception:
            quantity = 0
        try:
            cost_price = float(str(row.get("cost_price") or "0").strip())
        except Exception:
            cost_price = 0.0

        out.append(
            {
                "symbol": ts_code,
                "asset_type": asset_type,
                "name": name,
                "quantity": quantity,
                "cost_price": cost_price,
            }
        )
    return out


def write_positions(rows, date_tag: str):
    fieldnames = ["symbol", "asset_type", "name", "quantity", "cost_price"]

